```class Solution {
public:
    int smallestValue(int n) {
        vector<bool> isPrime(n + 1, true);
        isPrime[0] = isPrime[1] = false;
        for (int i = 2; i * i <= n; i++) {
            if (isPrime[i]) {
                for (int j = i * i; j <= n; j += i) {
                    isPrime[j] = false;
                }
            }
        }
        int res = n;
        while (true) {
            int sum = 0;
            for (int i = 2; i <= res; i++) {
                if (isPrime[i] && res % i == 0) {
                    while (res % i == 0) {
                        sum += i;
                        res /= i;
                    }
                }
            }
            if (sum == res) break;
            res = sum;
        }
        return res;
    }
};
